let
    BaseRows = Table.FromRows(
        {
            {"C1", "ABC Corp", "Enterprise"},
            {"C2", "XYZ Ltd", "SMB"},
            {"C3", "Delta Inc", "Enterprise"}
        },
        type table [CustomerID = text, CustomerName = text, Segment = text]
    ),
    // TODO: update file path to the actual location of Address.xlsx
    ExcelSource = Excel.Workbook(File.Contents("C:\data\Address.xlsx"), null, true),
    Sheet1 = ExcelSource{[Item="Sheet1", Kind="Sheet"]}[Data],
    PromotedHeaders = Table.PromoteHeaders(Sheet1, [PromoteAllScalars=true]),
    JoinedData = Table.NestedJoin(BaseRows, {"CustomerID"}, PromotedHeaders, {"CustomerID"}, "AddressData", JoinKind.LeftOuter),
    ExpandedAddress = Table.ExpandTableColumn(JoinedData, "AddressData", {"Customer Adress"}, {"Customer Adress"}),
    RenamedColumns = Table.RenameColumns(ExpandedAddress, {
        {"CustomerID", "Customer ID"},
        {"CustomerName", "Customer Name"}
    }),
    SelectedColumns = Table.SelectColumns(RenamedColumns, {"Customer ID", "Customer Name", "Segment", "Customer Adress"}),
    Output = Table.TransformColumnTypes(SelectedColumns, {
        {"Customer ID", type text},
        {"Customer Name", type text},
        {"Segment", type text},
        {"Customer Adress", type text}
    })
in
    Output

let
    Source = Table.FromRows(
        {
            {"P1", "Laptop", "Hardware"},
            {"P2", "Mouse", "Accessories"},
            {"P3", "Monitor", "Hardware"}
        },
        type table [ProductID = text, ProductName = text, Category = text]
    ),
    ProductGroupMap = Table.FromRows(
        {
            {"P1", "Hard"},
            {"P2", "ACC"}
        },
        type table [Key = text, GroupValue = text]
    ),
    JoinedWithGroup = Table.NestedJoin(Source, {"ProductID"}, ProductGroupMap, {"Key"}, "MappedGroup", JoinKind.LeftOuter),
    ExpandedGroup = Table.ExpandTableColumn(JoinedWithGroup, "MappedGroup", {"GroupValue"}, {"ProductGroupe"}),
    FilledNulls = Table.ReplaceValue(ExpandedGroup, null, "N/A", Replacer.ReplaceValue, {"ProductGroupe"}),
    RenamedColumns = Table.RenameColumns(FilledNulls, {
        {"ProductID", "Product ID"},
        {"ProductName", "Product Name"},
        {"ProductGroupe", "Product Groupe"}
    }),
    SelectedColumns = Table.SelectColumns(RenamedColumns, {"Product ID", "Product Name", "Category", "Product Groupe"}),
    Output = Table.TransformColumnTypes(SelectedColumns, {
        {"Product ID", type text},
        {"Product Name", type text},
        {"Category", type text},
        {"Product Groupe", type text}
    })
in
    Output
